// Worked focus: http-ts-json-boundary-validation — Serialize intentional JSON and validate unknown decoded values before admitting them to trusted domain types. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_fields_representations_2(contentType: string, acceptedTypes: readonly string[], bodyBytes: number): { mediaType: string; accepted: boolean } {
  const mediaType = contentType.split(";", 1)[0]?.trim().toLowerCase() ?? "";
  if (bodyBytes < 0 || bodyBytes > 1_048_576) return { mediaType, accepted: false };
  return { mediaType, accepted: acceptedTypes.includes(mediaType) };
}

